from functools import lru_cache

class Solution(object):
    def totalWaviness(self, num1, num2):
        def solve(limit):
            s = str(limit)
            n = len(s)
            # dp(pos, tight, d1, d2, started) -> (count, total_waviness)
            # d1 = last digit placed (-1 if none), d2 = second-to-last (-1 if none)
            @lru_cache(maxsize=None)
            def dp(pos, tight, d1, d2, started):
                if pos == n:
                    return (1, 0)
                hi = int(s[pos]) if tight else 9
                total_c = 0
                total_w = 0
                for d in range(0, hi + 1):
                    nt = tight and (d == hi)
                    if not started and d == 0:
                        c, w = dp(pos + 1, nt, -1, -1, False)
                    else:
                        # Check if d1 is a peak or valley
                        # d1 is interior if: d2 != -1 (has left neighbor) AND pos < n (has right neighbor = d)
                        # Also d1 is not the last digit: pos is placing pos-th digit now,
                        # d1 is at pos-1 and NOT last iff pos <= n-1 (always true here since pos < n)
                        # BUT: d1 IS the last digit when pos == n-1 and d is the last
                        # At pos == n-1, d is the final digit; d1 = second-to-last = interior iff d2 != -1
                        # Actually: d1 was placed at pos-1; it's interior iff it has both neighbors
                        # Left neighbor = d2 (if d2 != -1), right neighbor = d (which we're placing now)
                        # d1 is the last digit only if pos-1 == n-1, i.e., pos == n, but we're in pos < n
                        # So d1 is NOT the last digit as long as d exists (which it does)
                        # d1 is interior iff d2 != -1 (has a left neighbor)
                        extra = 0
                        if d1 != -1 and d2 != -1:
                            if d1 > d2 and d1 > d:
                                extra = 1  # peak
                            elif d1 < d2 and d1 < d:
                                extra = 1  # valley
                        c, w = dp(pos + 1, nt, d, d1, True)
                        w += extra * c
                    total_c += c
                    total_w += w
                return (total_c, total_w)
            _, w = dp(0, True, -1, -1, False)
            dp.cache_clear()
            return w
        return solve(num2) - solve(num1 - 1)
